from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class RetroQuadrant(str, Enum):
    WENT_WELL        = "went_well"
    IMPROVEMENT      = "improvement"
    LEARNED          = "learned"
    ACTION_ITEMS     = "action_items"

@dataclass
class RetroObservation:
    quadrant: RetroQuadrant
    text: str
    submitted_by: str
    vote_count: int = 0
    linked_action_item_ids: list[str] = field(default_factory=list)

@dataclass
class RetroActionItem:
    action_id: str
    description: str
    owner: str
    due_date: date
    priority: str         # "P1" | "P2" | "P3" | "P4"
    source_observations: list[str] = field(default_factory=list)  # RetroObservation texts
    committed_to_sprint: bool = False
    completed: bool = False

    def is_overdue(self, today: date) -> bool:
        return not self.completed and today > self.due_date

@dataclass
class LaunchRetrospective:
    feature_name: str
    retro_date: date
    launch_date: date
    facilitator: str
    attendees: list[str] = field(default_factory=list)
    observations: list[RetroObservation] = field(default_factory=list)
    action_items: list[RetroActionItem] = field(default_factory=list)

    def committed_items(self) -> list[RetroActionItem]:
        return [a for a in self.action_items if a.committed_to_sprint]

    def backlog_items(self) -> list[RetroActionItem]:
        return [a for a in self.action_items if not a.committed_to_sprint]

    def quadrant_summary(self) -> dict[str, int]:
        counts = {q.value: 0 for q in RetroQuadrant}
        for obs in self.observations:
            counts[obs.quadrant.value] += 1
        return counts

    def health_check(self) -> list[str]:
        issues = []
        if not self.committed_items():
            issues.append("no action items committed to sprint — retro may not drive change")
        unowned = [a for a in self.action_items if not a.owner]
        if unowned:
            issues.append(f"{len(unowned)} action items have no owner")
        no_due_date = [a for a in self.action_items if not a.due_date]
        if no_due_date:
            issues.append(f"{len(no_due_date)} action items have no due date")
        return issues

from dataclasses import dataclass
from datetime import date

@dataclass
class ActionItemTracker:
    retro_date: date
    feature_name: str

    def overdue_items(
        self,
        retro: "LaunchRetrospective",
        today: date,
    ) -> list[RetroActionItem]:
        return [a for a in retro.action_items if a.is_overdue(today)]

    def completion_rate(self, retro: "LaunchRetrospective") -> float:
        if not retro.action_items:
            return 0.0
        return sum(1 for a in retro.action_items if a.completed) / len(retro.action_items)

    def t30_readiness(
        self,
        retro: "LaunchRetrospective",
        review_date: date,
    ) -> str:
        committed = retro.committed_items()
        completed_committed = [a for a in committed if a.completed]
        overdue = self.overdue_items(retro, review_date)
        if not committed:
            return "WARNING: no committed items — T+30 review cannot evaluate retro impact"
        rate = len(completed_committed) / len(committed)
        if rate == 1.0:
            return f"READY: all {len(committed)} committed items completed"
        if overdue:
            return f"PARTIAL: {len(completed_committed)}/{len(committed)} done; {len(overdue)} overdue"
        return f"IN PROGRESS: {len(completed_committed)}/{len(committed)} done; none overdue"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class LessonEntry:
    lesson_id: str
    feature_name: str
    launch_date: date
    category: ActionItemCategory
    context: str        # what situation produced this learning
    learning: str       # the insight itself
    action_taken: str   # what the team changed as a result
    outcome: str        # whether the action resolved the issue (fill in post-action)
    tags: list[str] = field(default_factory=list)  # searchable keywords

    def to_knowledge_article(self) -> str:
        return (
            f"## {self.lesson_id}: {self.category.value}\n\n"
            f"**Feature:** {self.feature_name} ({self.launch_date})\n\n"
            f"**Context:** {self.context}\n\n"
            f"**Learning:** {self.learning}\n\n"
            f"**Action taken:** {self.action_taken}\n\n"
            f"**Outcome:** {self.outcome or 'pending'}\n\n"
            f"**Tags:** {', '.join(self.tags)}"
        )

@dataclass
class LessonsLearnedRegistry:
    entries: list[LessonEntry] = field(default_factory=list)

    def add(self, entry: LessonEntry) -> None:
        self.entries.append(entry)

    def by_category(self, category: ActionItemCategory) -> list[LessonEntry]:
        return [e for e in self.entries if e.category == category]

    def search(self, keyword: str) -> list[LessonEntry]:
        kw = keyword.lower()
        return [
            e for e in self.entries
            if kw in e.learning.lower()
            or kw in e.context.lower()
            or any(kw in tag for tag in e.tags)
        ]

    def prompt_engineering_lessons(self) -> list[LessonEntry]:
        return self.by_category(ActionItemCategory.PROMPT_ENGINEERING)
